import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Not Boring — 2026-05-25","description":"","frontmatter":{"title":"Not Boring — 2026-05-25","date":"2026-05-25T00:00:00.000Z","source":"Not Boring","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-25-not-boring.md","filePath":"research/ai-news/2026-05/2026-05-25-not-boring.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-25-not-boring.md"};function i(n,e,l,h,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🚀-not-boring-—-2026-05-25" tabindex="-1">🚀 Not Boring — 2026-05-25 <a class="header-anchor" href="#🚀-not-boring-—-2026-05-25" aria-label="Permalink to &quot;🚀 Not Boring — 2026-05-25&quot;">​</a></h1><blockquote><p>Packy McCormick 的科技商業策略深度文；以敘事帶動的長篇市場分析 來源：<a href="https://www.notboring.co/feed" target="_blank" rel="noreferrer">Not Boring</a></p></blockquote><hr><h2 id="weekly-dose-of-optimism-194" tabindex="-1"><a href="https://www.notboring.co/p/weekly-dose-of-optimism-194" target="_blank" rel="noreferrer">Weekly Dose of Optimism #194</a> <a class="header-anchor" href="#weekly-dose-of-optimism-194" aria-label="Permalink to &quot;[Weekly Dose of Optimism #194](https://www.notboring.co/p/weekly-dose-of-optimism-194)&quot;">​</a></h2><p><em>🚀 Not Boring | 2026-05-22</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!dnXa!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fb67bd8bd-37fc-420a-bdc8-309e8b3cc10d_1200x600.png" target="_blank" rel="noreferrer"></a></p><p>Hi friends 👋,</p><p>Happy Friday and welcome to our 194th Weekly Dose of Optimism. I&#39;m emailing you from beautiful Utah, where I attended the Abundance Institute Gala last night and got to talk nuclear with Oklo&#39;s Jake DeWitte and General Matter&#39;s Scott Nolan, and where I&#39;ll be spending today at the state&#39;s Operation Gigawatt Conference.</p><p>It&#39;s hard not to feel the optimism in the mountain air. When we started writing the Dose a few years back, nuclear was a controversial dream. Today, we&#39;re heading into the Memorial Day Weekend that kicks off the summer during which multiple new reactors will go critical for the first time.</p><p>Plus, you&#39;re about to read one of the most action-packed Doses in Dose history.</p><p>Things are moving fast, and mostly for the better. Happy Memorial Day Weekend, y&#39;all.</p><hr><h4 id="today-s-weekly-dose-if-brought-to-you-by-lightwork" tabindex="-1">Today&#39;s Weekly Dose if brought to you by… <a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Lightwork</a> <a class="header-anchor" href="#today-s-weekly-dose-if-brought-to-you-by-lightwork" aria-label="Permalink to &quot;Today&#39;s Weekly Dose if brought to you by… [Lightwork](http://lightworkhome.com/notboring)&quot;">​</a></h4><p><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer"></a></p><p><em>It turns out, my house has been making me worse at writing. Sorry about that. I have it under control now.</em></p><p><em><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Lightwork</a> came by my place recently and tested our air and water quality, light sources, likelihood of mold, electromagnetic exposure (turns out <a href="https://www.notboring.co/p/electromagnetism-secretly-runs-the" target="_blank" rel="noreferrer">electromagnetism does run the world</a>), and household products. It was an awesome experience. I learned a lot, including that my home&#39;s air quality and lighting were undermining my energy levels, our shower water was full of VOCs whose vapor I was inhaling, and a whole lot more.</em></p><p><em>Lightwork &#39;s assessments are concierge evaluations where they test every aspect of your home that could be impacting your health, produce a science-backed, in-depth report on all their findings, and then help you fix all the issues they uncover. I recommend them. Check them out!</em></p><p><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Book a Free Consultation Today</a></p><hr><h4 id="_1-retatrutide-stuns-in-phase-3-obesity-trial" tabindex="-1">(1) <a href="https://investor.lilly.com/news-releases/news-release-details/lillys-triple-agonist-retatrutide-delivered-powerful-weight-loss" target="_blank" rel="noreferrer">Retatrutide Stuns In Phase 3 Obesity Trial</a> <a class="header-anchor" href="#_1-retatrutide-stuns-in-phase-3-obesity-trial" aria-label="Permalink to &quot;(1) [Retatrutide Stuns In Phase 3 Obesity Trial](https://investor.lilly.com/news-releases/news-release-details/lillys-triple-agonist-retatrutide-delivered-powerful-weight-loss)&quot;">​</a></h4><p><em>Eli Lily</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!ON-_!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff5a18d85-0c0b-4433-979e-90d2e7bbd40d_1286x1616.jpeg" target="_blank" rel="noreferrer"></a></p><p>Yesterday morning, Eli Lilly reported topline results from TRIUMPH-1, the Phase 3 trial for retatrutide in adults with obesity and at least one weight-related comorbidity. Here&#39;s a <a href="https://x.com/maxmarchione/status/2057482589305450738?s=20" target="_blank" rel="noreferrer">summary of the results</a> from Superpower founder and peptide enthusiast Max Marchione:</p><ul><li><p>28.3% bodyweight lost on 12mg over 80 weeks</p></li><li><p>70.3 pounds on avg. or 31.9 kg</p></li><li><p>45.3% of patients hit 30%+ weight loss (this is bariatric surgery territory)</p></li><li><p>30.3% weight loss (85 lbs) at 104 weeks in higher-BMI patients</p></li><li><p>65.3% of 12mg patients dropped below the obesity BMI threshold</p></li><li><p>19% loss on 4mg over 80 weeks (47.2 lbs) with fewer dropouts than placebo (4.1% vs 4.9%)</p></li><li><p>significant drops in blood pressure, triglycerides, non-HDL cholesterol, waist circumference, and hsCRP</p></li><li><p>no cardiac or liver signals</p></li></ul><p>These are bariatric surgery results in a shot, with a bunch of freebies thrown in.</p><p>People have been excited about reta on social media for a while, but it&#39;s still gray market, so this is a key step towards getting it to the general public, and just an astonishing set of results. People are losing 28.3% of their bodyweight, or 70 pounds, in less than two years!</p><p>For context, Zepbound (tirzepatide) tops out around 20-22% weight loss in its big trials, and the previous-generation Wegovy (semaglutide) at around 15%.</p><p>Retatrutide is the first triple hormone receptor agonist (GIP + GLP-1 + glucagon). We previewed this back in <a href="https://www.notboring.co/p/weekly-dose-of-optimism-175" target="_blank" rel="noreferrer">Dose #175</a>, in our piece on grey-market peptides and Gen3 GLP-1/GIP/glucagon agonists. The author of the essay we covered, <em><a href="https://vectorculture.substack.com/p/not-for-human-consumption" target="_blank" rel="noreferrer">Not for Human Consumption</a>,</em> called these drugs &quot;the holy grail of weight loss medications&quot; before any of them had a Phase 3 readout. Now one of them does.</p><p>This is Lebron-level. Unbelievably hyped out of the gate, and then exceeds the hype.</p><p>As with all of these miracle drugs, there are positive side effects beyond weight loss. Retatrutide reduced osteoarthritis knee pain by an average of 75.8%, with more than 1 in 8 patients reporting they were completely free of knee pain at the end of the trial. LDL cholesterol dropped 20%. 72% of prediabetic participants returned to normal blood sugar levels. Seven more Phase 3 readouts are expected this year, including diabetes, sleep apnea, chronic back pain, and cardiorenal outcomes.</p><p>Get ready to get hot and healthy. It&#39;s Reta Summer (in 2027).</p><h4 id="_2-colossal-biosciences-hatches-chick-from-artificial-eggs" tabindex="-1"><strong>(2)<a href="https://x.com/colossal/status/2056708864096018584?s=20" target="_blank" rel="noreferrer">Colossal Biosciences Hatches Chick From Artificial Eggs</a></strong> <a class="header-anchor" href="#_2-colossal-biosciences-hatches-chick-from-artificial-eggs" aria-label="Permalink to &quot;**(2)[Colossal Biosciences Hatches Chick From Artificial Eggs](https://x.com/colossal/status/2056708864096018584?s=20)**&quot;">​</a></h4><p>&quot;Before we named the stars, before we mapped the atom, we asked ourselves an impossible question: which came first, the chicken or the egg?&quot;</p><p>On Monday, Ben Lamm&#39;s Colossal Biosciences announced that it has hatched 26 healthy chicks from a fully artificial egg, an oval printed shell coated in an oxygen-permeable membrane that lets an embryo develop from poured-in yolk to pipping bird, without a biological eggshell. Researchers crack a freshly laid fertilized egg, pour the contents into the artificial shell (Colossal adds ground-up calcium back in, because the embryo eats the shell as it grows), and watch through the top window as eyes form, vasculature spreads, and, 18 days later, a chick taps its way out.</p><p>Real scientists will tell you (and MIT Tech Review&#39;s Antonio Regalado dutifully <a href="https://www.technologyreview.com/2026/05/19/1137471/colossal-biosciences-is-growing-chickens-in-a-3d-printed-container/" target="_blank" rel="noreferrer">did</a>) that growing birds outside the shell isn&#39;t new. A Japanese group hatched quail in 1998. Katsuya Obara hatched chickens under transparent plastic film in 2024. Colossal&#39;s marketing is, per Regalado, &quot;pure Hollywood.&quot; Which is kind of fair but too clucking cynical.</p><p>Colossal&#39;s real engineering advance is the membrane, which lets the embryo pull enough oxygen from ambient air that the system doesn&#39;t need supplemental gas. Previous shell-less methods did, and chicks tended to die. I like the version in which the chicks live, Regalado.</p><p>While this experiment was on a chicken, we have plenty of those. Colossal likes to de-extinct. Its stated goal is the 12-foot, 500-pound South Island giant moa, which laid four-liter eggs no living bird is large enough to surrogate. Colossal staff are reportedly already calling the prototype scaled-up version the &quot;salad spinner.&quot; More immediately, the artificial egg is a tool for genetic rescue of endangered birds and, as per our discussion in <a href="https://www.notboring.co/p/weekly-dose-of-optimism-186" target="_blank" rel="noreferrer">Dose #186</a> with not boring capital portfolio company <a href="https://neion.bio/" target="_blank" rel="noreferrer">Neion Bio</a>, a substrate for transgenic chickens producing therapeutic proteins in egg whites at a fraction of mammalian cell culture costs.</p><p>This is the first member of what Colossal calls its &quot;exogenous development&quot; family. Up next: artificial wombs for marsupials.</p><p>With this chicken breakthrough, it feels like humans have crossed a road.</p><h4 id="_3-spacex-launches-s-1" tabindex="-1">(3) <a href="https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm" target="_blank" rel="noreferrer">SpaceX Launches S-1</a> <a class="header-anchor" href="#_3-spacex-launches-s-1" aria-label="Permalink to &quot;(3) [SpaceX Launches S-1](https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm)&quot;">​</a></h4><blockquote><p><em>For the entirety of its existence, human civilization has lived on a single celestial body: Earth. The current paradigm, in which human civilization is confined to one planet, exposes humanity to existential threats that are unpredictable and uncontrollable on a planetary scale. By moving beyond the only home we have ever known, we ensure species-level redundancy and that the light of consciousness will not be tied to a single planet subject to the inevitable hazards of a harsh and vast universe. We do not want humans to have the same fate as dinosaurs.</em></p></blockquote><p><a href="https://substackcdn.com/image/fetch/$s_!NVG3!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1793b624-cf49-40fe-b276-ad4daa692c2c_1586x826.png" target="_blank" rel="noreferrer"></a></p><p>On Wednesday, SpaeX dropped what may have been the most highly-anticipated S-1 in the history of the planet (until Anthropic files later this year). You can read it <a href="https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm" target="_blank" rel="noreferrer">here</a>.</p><p>Financial highlights include:</p><ul><li><p><strong>Revenue:</strong> $4.69B (run-rate ~$19B)</p></li><li><p><strong>Operating loss:</strong> $(1.94B), but Adjusted EBITDA of +$1.13B</p></li><li><p><strong>Connectivity (Starlink) prints cash:</strong> $3.26B revenue, $1.19B operating income in just the first quarter. Its revenue is growing ~50% per year, and profitability is growing faster.</p></li><li><p><strong>AI is losing money for now …:</strong> $818M revenue, $(2.47B) operating loss in Q1. Capex on AI alone was $7.7B in Q1, more than Space ($1.05B) and Connectivity ($1.33B) combined, by far.</p></li><li><p><strong>But has the monster TAM</strong> : AI infra, consumer subscriptions, digital advertising, and enterprise applications - the AI segment - has a company-estimated TAM of $26.5 trillion, which seems small when you consider the size of the universe and the potential to spread Enterprise Applications throughout it.</p></li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!P8z4!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff1d17734-2cbc-4938-96be-19e0ac4ebbb6_1262x802.png" target="_blank" rel="noreferrer"></a></p><p>SpaceX also disclosed that it&#39;s doing a <em>second</em> compute deal with Anthropic, in which Dario &amp; Co. will pay SpaceX $1.25 billion <em>per month</em> for Colossus 2, which is nearly as much as entire SpaceX makes now. For now, it&#39;s selling compute on earth, but per the S-1, it plans to begin deploying orbital compute in 2028 and scale it to 100 GW of compute launched annually, which would make Colossus seem like a pale blue dot.</p><p>Starlink, which had been the bull case until AI, is at 9,600 satellites, 10.3 million subscribers across 164 countries, and now accounts for ~75% of all active maneuverable satellites in orbit.</p><p>There is no one operating at a higher level than Elon and the SpaceX team, across everything from terrestrial data centers to rockets to satellites to, soon, Terafab. After more than 20 years, it&#39;s awesome to see the company go public (and generate some much-needed DPI for the venture and seven-layer-SPV ecosystems). Is the price a little high? Maybe, yeah, sure. But what would you pay to own a <em><a href="https://www.notboring.co/p/scarce-assets" target="_blank" rel="noreferrer">Scarce Asset</a></em> that catches Statue of Liberty-sized rockets with chopsticks…</p><p>We&#39;ll find out in June.</p><p>In the meanting, after scrapping the launch of Starship v3 last night, SpaceX is giving it another go today. What a way to launch summer.</p><h4 id="_4-gpt-5-5-pro-makes-breakthrough-on-erdos-planar-distance-problem" tabindex="-1">(4) <a href="https://x.com/OpenAI/status/2057176201782075690?s=20" target="_blank" rel="noreferrer">GPT 5.5 Pro Makes Breakthrough on Erdős Planar Distance Problem</a> <a class="header-anchor" href="#_4-gpt-5-5-pro-makes-breakthrough-on-erdos-planar-distance-problem" aria-label="Permalink to &quot;(4) [GPT 5.5 Pro Makes Breakthrough on Erdős Planar Distance Problem](https://x.com/OpenAI/status/2057176201782075690?s=20)&quot;">​</a></h4><p>Take <em>n</em> dots on a piece of paper. How many pairs of dots can sit exactly one unit apart from each other?</p><p>Paul Erdős posed this in 1946, conjectured the answer grows just barely faster than <em>n</em> , and offered cash for a resolution. For 80 years, the best constructions anyone could find were boring square grids, and most of combinatorial geometry treated Erdős&#39;s upper bound as essentially right.</p><p>This week, an internal general-purpose OpenAI reasoning model produced a proof that disproves it. The model isn&#39;t math-specific, it just thought for a long time and burned an <a href="https://x.com/willdepue/status/2057213893857165701?s=20" target="_blank" rel="noreferrer">estimated</a> ~$1,000 max worth of tokens, which is pretty affordable for an 80 year old unsolved problem! It found that there&#39;s an infinite family of point arrangements that beat the grid, polynomially. Erdős was wrong, and his &quot;favorite problem&quot; is settled.</p><p>How&#39;d it pull it off? Instead of more clever geometry, it pulled in algebraic number theory (specifically, <em>infinite class field towers</em> and Golod-Shafarevich theory, of course, why didn&#39;t I think of that) to construct number systems with the right symmetries, then read the geometric configurations off of those. No human had tried this connection. Thomas Bloom thinks it will unlock other long-stuck problems in discrete geometry.</p><p>And, importantly, it&#39;s verified. Last October, OpenAI <a href="https://x.com/kevinweil/status/1843..." target="_blank" rel="noreferrer">claimed</a> GPT-5 had solved ten Erdős problems; on inspection, it had just surfaced answers from the literature. This time, it got external review by Fields Medalist Tim Gowers and Will Sawin at Princeton, with a companion paper. Gowers&#39;s verdict: &quot;if a human had written the paper and submitted it to the <em>Annals of Mathematics</em> , I would have recommended acceptance without any hesitation.&quot; It also got endorsements from Noga Alon, Melanie Wood, Arul Shankar. Shankar said the models &quot;are capable of having original ingenious ideas, and then carrying them out to fruition.&quot; The full proof is available as a public PDF.</p><p>Ten months ago, frontier models were at IMO-gold level. Really smart high schoolers, basically. Now, they&#39;re doing <em>Annals</em> -worthy novel work.</p><p>I&#39;ve been more skeptical about AI than I normally am about new technologies, and less excited than the average person in tech. Per the evidence that keeps coming out, I&#39;ve been wrong. On the business side and the capabilities side, the pace has been truly remarkable, and I can&#39;t wait to see what problems they&#39;ll solve for us in the years ahead.</p><h4 id="_5-sendcutsend-raises-110m-at-1b-valuation" tabindex="-1">(5) <a href="https://x.com/jimbelosic/status/2056757837951574355?s=20" target="_blank" rel="noreferrer">SendCutSend Raises $110M at $1B Valuation</a> <a class="header-anchor" href="#_5-sendcutsend-raises-110m-at-1b-valuation" aria-label="Permalink to &quot;(5) [SendCutSend Raises $110M at $1B Valuation](https://x.com/jimbelosic/status/2056757837951574355?s=20)&quot;">​</a></h4><p><em>Jim Belosic (SendCutSend)</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!VYfO!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F61e3f89b-e4f6-4076-939a-0b818a392a68_1200x480.jpeg" target="_blank" rel="noreferrer"></a></p><p>Jim Belosic started SendCutSend in 2018 because he couldn&#39;t get custom metal parts fast enough for the cars and motorcycles he was restoring. Eight years later, bootstrapped to this point on credit cards, savings, a PayPal loan, and bank-financed machines, the Reno laser-cutting and bending shop is doing roughly $200 million in revenue, growing 100% year over year, and turning into one of the most important on-demand manufacturers in America.</p><p>Austin Vernon&#39;s February essay <em><a href="https://www.austinvernon.site/blog/manufacturing.html" target="_blank" rel="noreferrer">Speed Can Reindustrialize America</a></em> is the best piece on why the company is so impressive and potentially important. Vernon&#39;s argument is that the US is great at high-volume manufacturing and terrible at low-volume, short-lead-time custom work because soft costs (quoting, programming, billing, all the white-collar overhead) swamp the actual fabrication cost on small orders. SendCutSend&#39;s whole company is an attack on soft costs: instant quotes, one-click buying, software-routed production. It&#39;s generating ~$275K revenue per employee, and the market would support a hell of a lot of employees.</p><p>Interestingly, Patrick Collison was the one person Vernon thanked for feedback, right above the &quot;Funding Opportunities Apendix.&quot;</p><p><a href="https://substackcdn.com/image/fetch/$s_!_kor!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F5202ecfd-5db0-4e94-9c9c-f41ebbe8273b_1076x286.png" target="_blank" rel="noreferrer"></a></p><p>And I guess Collison took it literally, because he reached out to Belosic about investing, and although SCS had never taken outside capital, he decided to take money from the Collisons, Sequoia (Andrew Reed), and Paradigm (Matt Huang) to go bigger, faster.</p><p>Jim and SCS are easy to root for and have become a cult classic over the past few years. Now, the cat&#39;s out of the bag, the money is in the bank, and IT&#39;S TIME TO BUILD.</p><p>In other great news for building stuff here, Amca raised $300M at $1B+ from Caffeinated and crew. Amca builds and modernize factories to design and produce critical aerospace and defense components that are supply-constrained and often sole-sourced.</p><p>Jai Malik&#39;s eighteen-month-old El Segundo startup already runs factories in California, Iowa, and New York, supplies components for the F-35, and uses its RAPID software platform to deliver parts to BAE, Airbus, Textron, Honeywell, and GE Aerospace 67% faster than the legacy defense supply chain. Now, it can make more of the critical components on which the country runs.</p><h4 id="extra-doses-science-breakthroughs-anthropic-valar-atomics-quantum-investment-grindslop" tabindex="-1">Extra Doses: Science Breakthroughs, Anthropic, Valar Atomics, Quantum Investment, Grindslop <a class="header-anchor" href="#extra-doses-science-breakthroughs-anthropic-valar-atomics-quantum-investment-grindslop" aria-label="Permalink to &quot;Extra Doses: Science Breakthroughs, Anthropic, Valar Atomics, Quantum Investment, Grindslop&quot;">​</a></h4><p><a href="https://www.notboring.co/p/weekly-dose-of-optimism-194" target="_blank" rel="noreferrer"> Read more </a></p><hr>',73)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
